mapper.select:
SELECT id, name, description, category, retrieval_strategy,
       chunk_strategy, chunk_size, chunk_overlap, separators_json,
       document_count, created_by_user_id, created_by_name,
       strategy_version, is_deleted, deleted_at, created_at, updated_at
  FROM km_knowledge_base


     AND category = #{category}


     AND name LIKE CONCAT('%', #{nameKeyword}, '%')


     AND is_deleted = #{isDeleted}


 ORDER BY created_at DESC
 LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
  FROM km_knowledge_base


     AND category = #{category}


     AND name LIKE CONCAT('%', #{nameKeyword}, '%')


     AND is_deleted = #{isDeleted}
